```tla
MODULE YoYoElection

CONSTANTS
  NATURAL_NUMBERS = {0..∞}
  SOURCE_NODE = true
  INTERNAL_NODE = false
  SINK_NODE = false
  INITIAL_STATE = {
    nodes: NATURAL_NUMBERS,
    phase: "",
    incomingNeighbors: {n: NATURAL_NUMBERS : n ∈ nodes},
    outgoingNeighbors: {n: NATURAL_NUMBERS : n ∈ nodes},
    mailbox: {n: {yes: NATURAL_NUMBERS, no: NATURAL_NUMBERS} : n ∈ nodes},
    currentNode: NATURAL_NUMBERS,
    currentPhase: ""
  }

SPECIFICATION

  (* Initialization *)
  Init(state: YoYoElection.State) ==
    state.nodes = NATURAL_NUMBERS
    state.phase = ""
    state.incomingNeighbors = {n: NATURAL_NUMBERS : n ∈ state.nodes}
    state.outgoingNeighbors = {n: NATURAL_NUMBERS : n ∈ state.nodes}
    state.mailbox = {n: {yes: NATURAL_NUMBERS, no: NATURAL_NUMBERS} : n ∈ state.nodes}
    state.currentNode = NATURAL_NUMBERS
    state.currentPhase = ""

  (* Phase Transition *)
  PhaseTransition(state: YoYoElection.State) ==
    IF state.phase = "down"
    THEN
      state.phase = "up"
      state.currentNode = NATURAL_NUMBERS
      state.currentPhase = ""
    ELSE
      state.phase = "down"
      state.currentPhase = ""

  (* Down Phase *)
  DownPhase(state: YoYoElection.State) ==
    IF state.phase = "down"
    THEN
      state.currentNode = NATURAL_NUMBERS
      state.currentPhase = ""
    ELSE
      state.currentPhase = "down"

  (* Up Phase *)
  UpPhase(state: YoYoElection.State) ==
    IF state.phase = "up"
    THEN
      state.currentPhase = "up"
    ELSE
      state.currentPhase = ""

  (* Node Type *)
  NodeType(state: YoYoElection.State) ==
    IF state.currentNode ∈ state.incomingNeighbors
    THEN SOURCE_NODE
    ELSE IF state.currentNode ∈ state.outgoingNeighbors
    THEN INTERNAL_NODE
    ELSE SINK_NODE

  (* Messages Sent *)
  MessagesSent(state: YoYoElection.State) ==
    {n: {yes: NATURAL_NUMBERS, no: NATURAL_NUMBERS} : n ∈ state.nodes}

  (* Stabilization *)
  Stabilization(state: YoYoElection.State) ==
    IF state.phase = "down"
    THEN
      IF state.currentPhase = "down"
      THEN
        IF state.currentNode ∈ state.incomingNeighbors
        THEN
          IF state.mailbox[state.currentNode].yes ∈ NATURAL_NUMBERS
          THEN
            state.currentNode = NATURAL_NUMBERS
            state.currentPhase = ""
          ELSE
            state.currentPhase = "up"
      ELSE
        state.currentPhase = "up"
    ELSE
      state.currentPhase = ""

  (* Invariants *)
  Invariants(state: YoYoElection.State) ==
    {n: SOURCE_NODE : n ∈ state.nodes}
    {n: INTERNAL_NODE : n ∈ state.nodes}
    {n: NATURAL_NUMBERS : n ∈ state.nodes}
    {n: NATURAL_NUMBERS : n ∈ state.incomingNeighbors}
    {n: NATURAL_NUMBERS : n ∈ state.outgoingNeighbors}
    {n: {yes: NATURAL_NUMBERS, no: NATURAL_NUMBERS} : n ∈ state.nodes}
